(function () {
  "use strict";

  // ── DevTools / inspect protection ───────────────────────────────────────
  // Block keyboard shortcuts only — right-click stays enabled
  document.addEventListener("keydown", e => {
    if (
      e.key === "F12" ||
      (e.ctrlKey && e.shiftKey && ["I","J","C","K"].includes(e.key.toUpperCase())) ||
      (e.ctrlKey && e.key.toUpperCase() === "U")
    ) { e.preventDefault(); e.stopPropagation(); return false; }
  });

  // Block text selection and copy everywhere except inputs/textareas
  document.addEventListener("selectstart", e => {
    if (!["INPUT","TEXTAREA"].includes(e.target.tagName)) e.preventDefault();
  });
  document.addEventListener("copy", e => {
    if (!["INPUT","TEXTAREA"].includes(document.activeElement.tagName)) e.preventDefault();
  });

  // Glitch effect + reload on DevTools detection
  let _devOpen = false;
  let _glitching = false;

  function triggerGlitch() {
    if (_glitching) return;
    _glitching = true;
    const body = document.body;
    let frame = 0;
    const glitchStyles = [
      "skewX(8deg) scaleY(1.04)",
      "skewX(-10deg) scaleY(0.96)",
      "skewX(5deg) translateX(6px)",
      "skewX(-6deg) translateX(-8px)",
      "scaleX(1.05) scaleY(0.95)",
      "none",
    ];
    const iv = setInterval(() => {
      body.style.filter   = frame % 2 === 0 ? "hue-rotate(90deg) brightness(2) contrast(3)" : "invert(1) brightness(0.5)";
      body.style.transform = glitchStyles[frame % glitchStyles.length];
      body.style.visibility = frame % 2 === 0 ? "hidden" : "visible";
      frame++;
      if (frame >= 10) {
        clearInterval(iv);
        body.style.filter    = "";
        body.style.transform = "";
        body.style.visibility = "visible";
        location.reload();
      }
    }, 60);
  }

  setInterval(() => {
    const threshold = 160;
    const open = (window.outerWidth  - window.innerWidth  > threshold) ||
                 (window.outerHeight - window.innerHeight > threshold);
    if (open && !_devOpen) {
      _devOpen = true;
      triggerGlitch();
    } else if (!open) {
      _devOpen = false;
    }
  }, 100);

  // ── Cyber background ─────────────────────────────────────────────────────
  (function initBg() {
    const canvas = document.getElementById("bgCanvas");
    const ctx    = canvas.getContext("2d");
    const chars  = "01アイウエオカキクケコサシスセソタチツテトナニヌネノ";
    let cols, drops;
    function resize() {
      canvas.width  = window.innerWidth;
      canvas.height = window.innerHeight;
      cols  = Math.floor(canvas.width / 20);
      drops = Array(cols).fill(1);
    }
    window.addEventListener("resize", resize);
    resize();
    setInterval(() => {
      ctx.fillStyle = "rgba(10,10,20,0.05)";
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = "rgba(106,13,173,0.35)";
      ctx.font = "14px monospace";
      drops.forEach((y, i) => {
        ctx.fillText(chars[Math.floor(Math.random() * chars.length)], i * 20, y * 20);
        if (y * 20 > canvas.height && Math.random() > 0.975) drops[i] = 0;
        drops[i]++;
      });
    }, 60);
  })();

  // ── State ────────────────────────────────────────────────────────────────
  let boardSize      = 25;
  let flippedCards   = [];
  let locked         = false;
  let moves          = 0;
  let seconds        = 0;
  let timerInterval  = null;
  let matchedIndices = new Set();
  let shuffleDisabled = false;
  let loginAttempts  = 0;
  let couponAttempts = 0;
  const MAX_ATTEMPTS = 5;

  const grid           = document.getElementById("grid");
  const movesEl        = document.getElementById("moves");
  const timerEl        = document.getElementById("timer");
  const starsEl        = document.getElementById("stars");
  const cornerMsg      = document.getElementById("cornerMsg");
  const restartBtn     = document.getElementById("restartBtn");
  const fragmentReveal = document.getElementById("fragmentReveal");
  const fragmentImg    = document.getElementById("fragmentImg");
  const loginPanelWrap = document.getElementById("loginPanelWrap");
  const loginPanel     = document.getElementById("loginPanel");
  const loginEmail     = document.getElementById("loginEmail");
  const loginPassword  = document.getElementById("loginPassword");
  const loginError     = document.getElementById("loginError");
  const loginBtn       = document.getElementById("loginBtn");
  const celebOverlay   = document.getElementById("celebOverlay");
  const couponCode     = document.getElementById("couponCode");
  const couponInput    = document.getElementById("couponInput");
  const couponError    = document.getElementById("couponError");
  const scratchBtn     = document.getElementById("scratchBtn");
  const flagOverlay    = document.getElementById("flagOverlay");
  const flagValue      = document.getElementById("flagValue");

  // ── Timer ────────────────────────────────────────────────────────────────
  function startTimer() {
    clearInterval(timerInterval);
    seconds = 0;
    timerInterval = setInterval(() => {
      seconds++;
      timerEl.textContent = `${String(Math.floor(seconds/60)).padStart(2,"0")}:${String(seconds%60).padStart(2,"0")}`;
      starsEl.textContent = seconds < 60 ? "⭐⭐⭐" : seconds < 120 ? "⭐⭐" : "⭐";
    }, 1000);
  }

  // ── Grid ─────────────────────────────────────────────────────────────────
  function buildGrid(size) {
    grid.innerHTML = "";
    for (let i = 0; i < size; i++) {
      const card = document.createElement("div");
      card.className = "card";
      card.dataset.index = i;
      card.innerHTML = `<div class="card-inner"><div class="card-front"></div><div class="card-back"></div></div>`;
      card.addEventListener("click", onCardClick);
      grid.appendChild(card);
    }
  }

  function applyMatchedState(indices) {
    matchedIndices = new Set(indices);
    document.querySelectorAll(".card").forEach(c => {
      const i = parseInt(c.dataset.index);
      if (matchedIndices.has(i)) {
        c.classList.add("matched");
        c.classList.remove("flipped");
      } else {
        c.classList.remove("matched", "flipped");
        // Clear stale symbol so reshuffled position shows correct symbol on next flip
        c.querySelector(".card-back").textContent = "";
      }
    });
  }

  // ── Card click ───────────────────────────────────────────────────────────
  async function onCardClick(e) {
    if (locked) return;
    const card  = e.currentTarget;
    const index = parseInt(card.dataset.index);
    if (matchedIndices.has(index)) return;
    if (flippedCards.find(c => c.index === index)) return;
    if (flippedCards.length >= 2) return;

    const res  = await fetch("/flip_card", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({index}) });
    const data = await res.json();
    if (data.error) return;

    card.querySelector(".card-back").textContent = data.symbol;
    card.classList.add("flipped");
    flippedCards.push({ index, symbol: data.symbol, el: card });

    if (flippedCards.length === 2) {
      locked = true;
      moves++;
      movesEl.textContent = moves;
      setTimeout(checkPair, 600);
    }
  }

  // ── Check pair ───────────────────────────────────────────────────────────
  async function checkPair() {
    const [a, b] = flippedCards;
    const res  = await fetch("/check_pair", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({index1:a.index, index2:b.index}) });
    const data = await res.json();

    if (data.match) {
      a.el.classList.remove("flipped"); b.el.classList.remove("flipped");
      a.el.classList.add("matched");    b.el.classList.add("matched");
      matchedIndices.add(a.index);      matchedIndices.add(b.index);

      if (data.first_match) {
        shuffleDisabled = true;
        showCornerMsg(data.corner_message);
      }

      if (data.game_won) {
        clearInterval(timerInterval);
        setTimeout(triggerWin, 500);
      }

      flippedCards = [];
      locked = false;
    } else {
      a.el.classList.remove("flipped"); b.el.classList.remove("flipped");
      flippedCards = [];

      if (data.scramble) {
        document.querySelectorAll(".card:not(.matched)").forEach(c => {
          c.classList.add("scrambling");
          setTimeout(() => c.classList.remove("scrambling"), 500);
        });
        setTimeout(async () => {
          const bd = await (await fetch("/get_board")).json();
          applyMatchedState(bd.matched);
          locked = false;
        }, 520);
      } else {
        locked = false;
      }
    }
  }

  // ── Win sequence ─────────────────────────────────────────────────────────
  function triggerWin() {
    showFragmentReveal();
    // Show login panel below image after scroll settles
    setTimeout(() => {
      loginPanelWrap.style.display = "block";
      // Trigger slide-in animation
      requestAnimationFrame(() => loginPanel.classList.add("visible"));
      // Scroll to login panel so player sees it
      setTimeout(() => loginPanelWrap.scrollIntoView({ behavior: "smooth", block: "start" }), 200);
    }, 1200);
  }

  function showFragmentReveal() {
    fragmentReveal.style.display = "flex";
    // Scroll to image first
    setTimeout(() => fragmentReveal.scrollIntoView({ behavior: "smooth", block: "center" }), 50);
    requestAnimationFrame(() => {
      fragmentImg.classList.add("fragment-glow");
      // Blink twice (4 toggles) then fade in
      let blinks = 0;
      fragmentImg.style.opacity = "1";
      const blinkInterval = setInterval(() => {
        fragmentImg.style.opacity = fragmentImg.style.opacity === "0" ? "1" : "0";
        blinks++;
        if (blinks >= 4) {
          clearInterval(blinkInterval);
          fragmentImg.style.opacity = "";
          fragmentImg.classList.add("fragment-fadein");
        }
      }, 220);
    });
  }

  // ── Corner message ───────────────────────────────────────────────────────
  let cornerTimeout = null;
  function showCornerMsg(text) {
    cornerMsg.textContent = text;
    cornerMsg.classList.add("visible");
    clearTimeout(cornerTimeout);
    cornerTimeout = setTimeout(() => cornerMsg.classList.remove("visible"), 3500);
  }

  // ── Danger alert ─────────────────────────────────────────────────────────
  const dangerAlert      = document.getElementById("dangerAlert");
  const dangerAlertTitle = document.getElementById("dangerAlertTitle");
  const dangerAlertMsg   = document.getElementById("dangerAlertMsg");

  function showDangerAlert(title, msg) {
    dangerAlertTitle.textContent = title;
    dangerAlertMsg.textContent   = msg;
    dangerAlert.classList.add("active");
    setTimeout(() => dangerAlert.classList.remove("active"), 1600);
  }

  // ── Login ────────────────────────────────────────────────────────────────
  loginBtn.addEventListener("click", async () => {
    loginError.textContent = "";
    if (loginAttempts >= MAX_ATTEMPTS) return; // already locked
    const email    = loginEmail.value.trim();
    const password = loginPassword.value.trim();
    if (!email || !password) { loginError.textContent = "Please fill in all fields."; return; }

    const res  = await fetch("/login", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({email, password}) });
    const data = await res.json();

    if (data.success) {
      loginPanelWrap.style.display = "none";
      loginPanel.classList.remove("visible");
      couponCode.textContent = data.coupon;
      celebOverlay.style.display = "flex";
      launchConfetti("confettiCanvas");
    } else {
      loginAttempts++;
      if (loginAttempts >= MAX_ATTEMPTS) {
        loginBtn.disabled = true;
        loginBtn.textContent = "Too many attempts. Access locked.";
        loginBtn.style.background = "#444";
        loginBtn.style.cursor = "not-allowed";
        loginError.textContent = "Maximum attempts reached. Access locked.";
        showDangerAlert("ACCESS LOCKED", "Too many failed attempts");
      } else {
        showDangerAlert("ACCESS DENIED", "Invalid credentials");
        loginError.textContent = data.message;
      }
    }
  });

  // ── Coupon scratch ───────────────────────────────────────────────────────
  scratchBtn.addEventListener("click", async () => {
    couponError.textContent = "";
    if (couponAttempts >= MAX_ATTEMPTS) return; // already locked
    const coupon = couponInput.value.trim();
    if (!coupon) { couponError.textContent = "Please enter the coupon code."; return; }

    const res  = await fetch("/redeem_coupon", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({coupon}) });
    const data = await res.json();

    if (data.success) {
      celebOverlay.style.display = "none";
      flagValue.textContent = data.flag;
      flagOverlay.style.display = "flex";
      launchConfetti("confettiCanvas2");
    } else {
      couponAttempts++;
      if (couponAttempts >= MAX_ATTEMPTS) {
        scratchBtn.disabled = true;
        scratchBtn.textContent = "Too many attempts. Locked.";
        scratchBtn.style.background = "#444";
        scratchBtn.style.cursor = "not-allowed";
        couponError.textContent = "Maximum attempts reached. Coupon locked.";
        showDangerAlert("CODE LOCKED", "Too many failed attempts");
      } else {
        showDangerAlert("INVALID CODE", "Wrong coupon code");
        couponError.textContent = data.message;
      }
    }
  });

  // ── Confetti ─────────────────────────────────────────────────────────────
  function launchConfetti(canvasId) {
    const canvas = document.getElementById(canvasId);
    const ctx    = canvas.getContext("2d");
    canvas.width  = canvas.offsetWidth;
    canvas.height = canvas.offsetHeight;

    const pieces = Array.from({length: 120}, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height - canvas.height,
      r: Math.random() * 8 + 4,
      d: Math.random() * 80 + 20,
      color: `hsl(${Math.random()*360},90%,60%)`,
      tilt: Math.random() * 10 - 10,
      tiltAngle: 0,
      tiltSpeed: Math.random() * 0.1 + 0.05,
    }));

    let frame;
    function draw() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      pieces.forEach(p => {
        p.tiltAngle += p.tiltSpeed;
        p.y += (Math.cos(p.d) + 2);
        p.x += Math.sin(p.tiltAngle) * 1.5;
        p.tilt = Math.sin(p.tiltAngle) * 12;
        if (p.y > canvas.height) { p.y = -10; p.x = Math.random() * canvas.width; }
        ctx.beginPath();
        ctx.lineWidth = p.r;
        ctx.strokeStyle = p.color;
        ctx.moveTo(p.x + p.tilt + p.r / 2, p.y);
        ctx.lineTo(p.x + p.tilt, p.y + p.tilt + p.r / 2);
        ctx.stroke();
      });
      frame = requestAnimationFrame(draw);
    }
    draw();
    setTimeout(() => cancelAnimationFrame(frame), 6000);
  }

  // ── Restart ──────────────────────────────────────────────────────────────
  restartBtn.addEventListener("click", async () => {
    clearInterval(timerInterval);
    await fetch("/restart", { method: "POST" });
    loginPanelWrap.style.display = "none";
    loginPanel.classList.remove("visible");
    celebOverlay.style.display = "none";
    flagOverlay.style.display  = "none";
    fragmentReveal.style.display = "none";
    fragmentImg.classList.remove("fragment-glow", "fragment-fadein");
    fragmentImg.style.opacity = "";
    init();
  });

  // ── Init ─────────────────────────────────────────────────────────────────
  async function init() {
    flippedCards    = [];
    locked          = false;
    shuffleDisabled = false;
    moves           = 0;
    movesEl.textContent = "0";
    timerEl.textContent = "00:00";
    starsEl.textContent = "⭐⭐⭐";
    cornerMsg.classList.remove("visible");
    loginEmail.value    = "";
    loginPassword.value = "";
    loginError.textContent  = "";
    couponInput.value   = "";
    couponError.textContent = "";

    // Reset attempt counters and button states
    loginAttempts  = 0;
    couponAttempts = 0;
    loginBtn.disabled = false;
    loginBtn.textContent = "LOGIN / SUBSCRIBE";
    loginBtn.style.background = "";
    loginBtn.style.cursor = "";
    scratchBtn.disabled = false;
    scratchBtn.textContent = "SCRATCH";
    scratchBtn.style.background = "";
    scratchBtn.style.cursor = "";

    const data = await (await fetch("/get_board")).json();
    boardSize       = data.board_size;
    shuffleDisabled = data.shuffle_disabled || false;
    buildGrid(boardSize);
    applyMatchedState(data.matched);
    startTimer();
  }

  init();
})();
